using UnityEngine;

/// <summary>
/// Tarefa #31 — trigger 2D colocado nas bordas/portas da cena de uma área:
/// quando o player entra, pede a <see cref="AreaManager"/> para carregar a
/// cena de <see cref="targetArea"/> (AreaData.sceneName) e reaparecer no
/// <see cref="AreaSpawnPoint"/> "targetSpawnPointId" dessa cena.
///
/// Ignorado enquanto já houver uma transição em curso
/// (AreaManager.TransitionPending) — evita pedidos duplicados se o player
/// permanecer no trigger durante o fade/carregamento.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class AreaTransition : MonoBehaviour
{
    [Header("Destino")]
    [Tooltip("Área/cena de destino (AreaData.sceneName).")]
    public AreaData targetArea;

    [Tooltip("ID do AreaSpawnPoint na cena de destino onde o player deve reaparecer (ex: \"EntradaOeste\"). Deve corresponder a um AreaSpawnPoint.spawnId existente nessa cena — idealmente também listado em targetArea.spawnPointIds.")]
    public string targetSpawnPointId;

    private void Awake()
    {
        var col = GetComponent<Collider2D>();
        if (col != null) col.isTrigger = true;
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        if (AreaManager.Instance == null) return;
        if (AreaManager.Instance.TransitionPending) return;

        AreaManager.Instance.RequestTransition(targetArea, targetSpawnPointId);
    }
}
